<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Bouncing Ball Playground</title>
<style>
  :root {
    --bg: #0e1116;
    --panel: #161b22;
    --accent: #58a6ff;
    --text: #e6edf3;
    --muted: #8b949e;
  }
  * { box-sizing: border-box; }
  html, body {
    margin: 0;
    height: 100%;
    background: radial-gradient(1200px 600px at 50% -10%, #1b2330 0%, var(--bg) 60%);
    color: var(--text);
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Helvetica, Arial, sans-serif;
    display: flex;
    align-items: center;
    justify-content: center;
  }
  .wrap {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 16px;
    padding: 24px;
  }
  h1 {
    margin: 0;
    font-size: 18px;
    letter-spacing: 0.5px;
    color: var(--muted);
    font-weight: 500;
  }
  .controls {
    display: flex;
    gap: 10px;
  }
  button {
    background: var(--panel);
    color: var(--text);
    border: 1px solid #2a313c;
    border-radius: 8px;
    padding: 9px 16px;
    font-size: 14px;
    cursor: pointer;
    transition: transform 0.08s ease, background 0.15s ease, border-color 0.15s ease;
  }
  button:hover { background: #1c232c; border-color: var(--accent); }
  button:active { transform: translateY(1px); }
  button.active { border-color: var(--accent); color: var(--accent); }
  canvas {
    background: #0a0d12;
    border: 1px solid #232a33;
    border-radius: 12px;
    box-shadow: 0 10px 40px rgba(0,0,0,0.5), inset 0 0 60px rgba(88,166,255,0.04);
    cursor: crosshair;
    display: block;
  }
  .hint {
    font-size: 12px;
    color: var(--muted);
  }
</style>
</head>
<body>
  <div class="wrap">
    <h1>Bouncing Ball Playground</h1>
    <canvas id="sim" width="500" height="500"></canvas>
    <div class="controls">
      <button id="drop">Drop Ball</button>
      <button id="play" class="active">Pause</button>
      <button id="clear">Clear</button>
    </div>
    <div class="hint">Click the canvas to spawn a ball where you click.</div>
  </div>

<script>
(function () {
  const canvas = document.getElementById('sim');
  const ctx = canvas.getContext('2d');
  const W = canvas.width;
  const H = canvas.height;

  const GRAVITY = 0.45;       // px per step^2 (downward)
  const RESTITUTION = 0.86;  // energy retained on bounce
  const FRICTION = 0.999;    // tiny air drag
  const SUBSTEPS = 6;         // for tunneling safety

  let balls = [];
  let playing = true;

  // Distinct, pleasant palette
  const palette = [
    '#ff7b72', '#58a6ff', '#3fb950', '#d2a8ff',
    '#ffa657', '#79c0ff', '#56d4dd', '#f0883e'
  ];

  function rand(a, b) { return a + Math.random() * (b - a); }

  function draw() {
    ctx.clearRect(0, 0, W, H);

    // subtle floor grid
    ctx.strokeStyle = 'rgba(88,166,255,0.05)';
    ctx.lineWidth = 1;
    for (let x = 0; x <= W; x += 50) {
      ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, H); ctx.stroke();
    }
    for (let y = 0; y <= H; y += 50) {
      ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(W, y); ctx.stroke();
    }

    for (const b of balls) {
      // soft glow
      const g = ctx.createRadialGradient(b.x, b.y, b.r * 0.2, b.x, b.y, b.r * 1.6);
      g.addColorStop(0, b.color);
      g.addColorStop(1, 'rgba(0,0,0,0)');
      ctx.fillStyle = g;
      ctx.globalAlpha = 0.35;
      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r * 1.6, 0, Math.PI * 2);
      ctx.fill();
      ctx.globalAlpha = 1;

      // body
      const body = ctx.createRadialGradient(
        b.x - b.r * 0.35, b.y - b.r * 0.35, b.r * 0.1,
        b.x, b.y, b.r
      );
      body.addColorStop(0, '#ffffff');
      body.addColorStop(0.25, b.color);
      body.addColorStop(1, b.color);
      ctx.fillStyle = body;
      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      ctx.fill();

      // rim
      ctx.strokeStyle = 'rgba(0,0,0,0.25)';
      ctx.lineWidth = 1;
      ctx.stroke();
    }
  }

  function physicsStep(dt) {
    const sdt = dt / SUBSTEPS;
    for (let s = 0; s < SUBSTEPS; s++) {
      for (const b of balls) {
        b.vy += GRAVITY * sdt;
        b.vx *= FRICTION;
        b.vy *= FRICTION;
        b.x += b.vx * sdt;
        b.y += b.vy * sdt;

        // left / right walls
        if (b.x - b.r < 0) {
          b.x = b.r;
          b.vx = -b.vx * RESTITUTION;
        } else if (b.x + b.r > W) {
          b.x = W - b.r;
          b.vx = -b.vx * RESTITUTION;
        }
        // top / floor
        if (b.y - b.r < 0) {
          b.y = b.r;
          b.vy = -b.vy * RESTITUTION;
        } else if (b.y + b.r > H) {
          b.y = H - b.r;
          b.vy = -b.vy * RESTITUTION;
          b.vx *= 0.98; // floor friction
        }
      }
    }
  }

  // Public API
  window.sim = {
    w: W,
    h: H,
    balls() {
      return balls.map(b => ({ x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r }));
    },
    addBall(x, y, vx = 0, vy = 0, r) {
      const radius = (typeof r === 'number' && r > 0) ? r : rand(12, 26);
      const color = palette[Math.floor(Math.random() * palette.length)];
      // keep inside bounds initially
      const cx = Math.max(radius, Math.min(W - radius, x));
      const cy = Math.max(radius, Math.min(H - radius, y));
      balls.push({ x: cx, y: cy, vx, vy, r: radius, color });
    },
    clear() {
      balls = [];
      draw();
    },
    step(dt = 1) {
      physicsStep(dt);
      draw();
    }
  };

  // UI wiring
  const dropBtn = document.getElementById('drop');
  const playBtn = document.getElementById('play');
  const clearBtn = document.getElementById('clear');

  dropBtn.addEventListener('click', () => {
    window.sim.addBall(rand(W * 0.2, W * 0.8), rand(40, 120), rand(-3, 3), 0);
  });

  playBtn.addEventListener('click', () => {
    playing = !playing;
    playBtn.textContent = playing ? 'Pause' : 'Play';
    playBtn.classList.toggle('active', playing);
  });

  clearBtn.addEventListener('click', () => {
    window.sim.clear();
  });

  canvas.addEventListener('click', (e) => {
    const rect = canvas.getBoundingClientRect();
    const x = (e.clientX - rect.left) * (W / rect.width);
    const y = (e.clientY - rect.top) * (H / rect.height);
    window.sim.addBall(x, y, rand(-2, 2), rand(-1, 1));
  });

  // Animation loop
  function loop() {
    if (playing) window.sim.step(1);
    requestAnimationFrame(loop);
  }

  // Seed a couple of balls for visual interest
  window.sim.addBall(150, 80, 2, 0);
  window.sim.addBall(350, 60, -1.5, 0);
  draw();
  loop();
})();
</script>
</body>
</html>
